args.sparql:
SELECT ?film ?filmLabel WHERE {
  wd:Q26285952 wdt:P577 ?wsReleaseDate .
  wd:Q103224547 wdt:P161 ?film .
  ?film wdt:P577 ?releaseDate .
  FILTER(?releaseDate > ?wsReleaseDate)
  OPTIONAL { ?film rdfs:label ?filmLabel . FILTER(LANG(?filmLabel) = 'en') }
} ORDER BY ?releaseDate LIMIT 1

SELECT ?film ?filmLabel WHERE {
  ?film wdt:P161 wd:Q103224547 ;
        wdt:P577 ?releaseDate .
  FILTER(?releaseDate > "2021-12-21"^^xsd:date)
  OPTIONAL { ?film rdfs:label ?filmLabel . FILTER(LANG(?filmLabel) = 'en') }
} ORDER BY ?releaseDate
LIMIT 1

SELECT ?film ?filmLabel WHERE {
  wd:Q4012787 wdt:P577 ?wsDate.
  ?film wdt:P161 wd:Q103224547;
        wdt:P577 ?releaseDate.
  FILTER(?releaseDate > ?wsDate)
  OPTIONAL { ?film rdfs:label ?filmLabel. FILTER(LANG(?filmLabel) = 'en') }
} ORDER BY ?releaseDate LIMIT 1
